INSERT INTO passages (id, title, topic, content, content_ja) VALUES (
INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(16, 6, 1, 'comprehension', 'What did Vera Rubin''s research reveal about galaxies?', '第2段落で、ヴェラ・ルービンとケント・フォードの研究により、渦巻銀河の端にある星が目に見える物質の質量だけでは説明できない速度で軌道を描いていること、そして銀河は見えない物質のハローに埋め込まれているに違いないことが明らかになったと述べられている。選択肢2がこの内容と一致する。', 2),
(17, 6, 2, 'fill_in_blank', 'Which of the following best fits in the blank [BLANK] in paragraph 4?', '第4段落は、1998年に宇宙の膨張が加速していることが発見されたと述べている。この発見は重力による減速の仮定に反し、それに続く[BLANK]は、この発見の帰結を述べるべき。宇宙のエネルギーの大部分を占める未知の力（暗黒エネルギー）の存在を示唆したという選択肢3が最適。', 3),
(18, 6, 3, 'comprehension', 'According to the passage, why has the search for dark matter particles been frustrating for physicists?', '第3段落で、XENON実験やLUX-ZEPLIN実験などの大規模な地下検出器が並外れた感度でWIMPを探してきたが決定的な検出に至っていないこと、直接的な証拠の持続的な欠乏（dearth）が代替理論の探求を促していると述べられている。選択肢4がこの内容を正確に反映している。', 4);
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(16, 1, 'Galaxies in the Coma Cluster are moving slower than predicted by gravitational models.'),
(16, 2, 'Stars at the edges of spiral galaxies orbit at speeds that require the existence of unseen matter to explain.'),
(16, 3, 'The visible matter in galaxies accounts for all of their gravitational effects.'),
(16, 4, 'Spiral galaxies emit a form of radiation that can be detected only by underground experiments.'),
(17, 1, 'confirmed that Einstein''s theory of general relativity was fundamentally flawed'),
(17, 2, 'proved that the universe would eventually collapse back on itself in a "Big Crunch"'),
(17, 3, 'implied the existence of a mysterious repulsive force—later called dark energy—driving the cosmos apart'),
(17, 4, 'demonstrated that Type Ia supernovae are unreliable indicators of cosmic distances'),
(18, 1, 'Underground laboratories have been shut down due to funding shortages.'),
(18, 2, 'Dark matter has already been detected but the results remain classified by governments.'),
(18, 3, 'Physicists have concluded that dark matter does not exist and have abandoned the search.'),
(18, 4, 'Despite using extraordinarily sensitive detectors, no definitive direct detection of dark matter particles has been achieved.');
